1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return no living cells for an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell (underpopulation, 0 neighbors)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells (underpopulation, 1 neighbor each)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	  it.todo("should keep a live cell alive with exactly 3 neighbors (survival)");
22	  it.todo("should kill a live cell with 4 neighbors (overpopulation)");
23	  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
24	  it.todo("should keep a block pattern unchanged (still life)");
25	  it.todo("should oscillate a blinker pattern (period-2 oscillator)");
26	});
27

1	export type Cell = [number, number];
2	
3	const neighborOffsets: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	export function nextGeneration(livingCells: Cell[]): Cell[] {
10	  const isAlive = (x: number, y: number) =>
11	    livingCells.some(([cx, cy]) => cx === x && cy === y);
12	
13	  const countLiveNeighbors = (x: number, y: number): number =>
14	    neighborOffsets.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
15	
16	  return livingCells.filter(([x, y]) => {
17	    const neighbors = countLiveNeighbors(x, y);
18	    return neighbors === 2 || neighbors === 3;
19	  });
20	}
